import { React, useState } from 'react'
import Button from '@mui/material/Button';
import { FormControl, FormLabel, Stack, Box, TextField } from '@mui/material';
import styled from '@emotion/styled'
import { Link, Navigate, useNavigate } from 'react-router-dom'
import useAuth from '../hooks/useAuth'
import supabaseClient from '../supabase'
import appTheme from '../theme';

const LoginForm = () => {

    const { user, setUser } = useAuth()

    const navigate = useNavigate()

    const [error, setError ] = useState()

    const dataUser = e => {
        setUser({
            ...user,
            [e.target.name]: e.target.value
        })
    }


    const handleSubmit = async(e) => {

        e.preventDefault()

        setError('')

        try {

            await supabaseClient.auth.signInWithPassword(user.email, user.password)
            
            navigate('/')

        } catch(error) {

            if ( error.code === "auth/user-not-found")
            {
                setError('El usuario ingresado no existe.');
            } else if ( error.code === "auth/wrong-password")
            {
                setError('La contraseña no es correcta.');
            } else if ( error.code === "auth/internal-error")
            {
                setError('Se debe ingresar la contraseña.');
            } else if ( error.code === "auth/invalid-email")
            {
                setError('Se debe ingresar un mail válido.');
            } else
            {
                setError('Se produjo un error. Volvé a intentar más tarde.');
            }
                
        }
        
    }
    

  return (
        <>
        {   
            <Stack sx={{
                    display: 'flex',
                    alignItems: 'center',
                }}>
                <FormControl >

                    <Box sx={{
                            margin: '5rem auto',
                            padding: '1rem',
                        }}>
                        <TextField label="Email" variant="standard" sx={{
                            width: '100%',
                            paddingBottom: '2rem',
                        }}
                        InputLabelProps={{
                            style: {
                                fontSize: '14px',
                                color: appTheme.palette.primary.main
                            }
                        }}
                        inputProps={{
                            style: {
                                breakBefore: {
                                    borderBottom: '1px solid #779A4A'
                                },
                                break: {
                                    borderBottom: '1px solid #779A4A'
                                }
                                
                            },
                        }}/>
                        <TextField label="Password" variant="standard" sx={{
                            width: '100%',
                        }}/>
                    </Box>
                    
                    <Button variant="contained" sx={{
                        textTransform: 'capitalize',
                        fontSize: '18px',
                        fontFamily: 'Poppins',
                        fontWeight: 700,
                        width: '100%',
                        marginTop: '6rem',
                        marginBottom: '1rem'
                    }}>Ingresar</Button>

                </FormControl>
            </Stack>            
}
        </>
  )
}

export default LoginForm
